  HomeDataModel.fromJson(dynamic json) {
    _status = json['status'];
    _language = json['language'];
    if (json['categories'] != null) {
      _categories = [];
      json['categories'].forEach((v) {
        _categories?.add(Categories.fromJson(v));
      });
    }
    if (json['featured_properties'] != null) {
      _featuredProperties = [];
      json['featured_properties'].forEach((v) {
        _featuredProperties?.add(FeaturedProperties.fromJson(v));
      });
    }if (json['projects'] != null) {
      _project = [];
      json['projects'].forEach((v) {
        _project?.add(ProjectResponse.fromJson(v));
      });
    }
    if (json['location_properties'] != null) {
      _locationProperties = [];
      json['location_properties'].forEach((v) {
        _locationProperties?.add(LocationProperties.fromJson(v));
      });
    }
  }
