  String? get language => _language;
  List<Categories>? get categories => _categories;
  List<FeaturedProperties>? get featuredProperties => _featuredProperties;
  List<ProjectResponse>? get project => _project;
  List<LocationProperties>? get locationProperties => _locationProperties;

  Map<String, dynamic> toJson() {
    final map = <String, dynamic>{};
    map['status'] = _status;
    map['language'] = _language;
    if (_categories != null) {
      map['categories'] = _categories?.map((v) => v.toJson()).toList();
    }
    if (_featuredProperties != null) {
      map['featured_properties'] = _featuredProperties?.map((v) => v.toJson()).toList();
    }if (_project != null) {
